import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Properly encoding user input before including it in the output HTML
        String output = "<div>" + Encode.forHtml(userInput) + "</div>";

        try {
            // Write the output to the webpage
            PrintWriter out = new PrintWriter("output.html");
            out.println(output);
            out.close();

            System.out.println("Output successfully written to output.html");
        } catch (IOException e) {
            System.err.println("Error writing output: " + e.getMessage());
        }
    }
}

